import React, { useState } from 'react';
import { Search, Bell, User, Settings, ChevronDown } from 'lucide-react';

const Header = () => {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [selectedWorkspace, setSelectedWorkspace] = useState('Workspace 1');

  const workspaces = ['Workspace 1', 'Workspace 2', 'Workspace 3'];

  return (
    <header className="bg-white border-b border-gray-200 px-6 py-3 flex items-center justify-between">
      {/* Left side - Workspace with Dropdown */}
      <div className="relative z-20">
        <button
          onClick={() => setIsDropdownOpen(!isDropdownOpen)}
          className="flex items-center gap-2 px-4 py-2 hover:bg-gray-50 rounded-lg transition-colors"
        >
          <div className="text-left">
            <h2 className="text-sm font-medium text-gray-500">Workspace</h2>
            <div className="flex items-center gap-1">
              <span className="text-lg font-semibold text-gray-900">{selectedWorkspace}</span>
              <ChevronDown size={18} className={`text-gray-600 transition-transform duration-200 ${isDropdownOpen ? 'rotate-180' : ''}`} />
            </div>
          </div>
        </button>

        {/* Dropdown Menu */}
        {isDropdownOpen && (
          <div className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-200 overflow-hidden">
            {workspaces.map((workspace) => (
              <button
                key={workspace}
                onClick={() => {
                  setSelectedWorkspace(workspace);
                  setIsDropdownOpen(false);
                }}
                className={`w-full text-left px-4 py-2 hover:bg-gray-50 transition-colors ${
                  selectedWorkspace === workspace ? 'bg-primary/10 text-primary' : 'text-gray-700'
                }`}
              >
                {workspace}
              </button>
            ))}
          </div>
        )}
      </div>
      
      {/* Center - Search Bar */}
      <div className="flex-1 max-w-md mx-auto px-4">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text"
            placeholder="Search..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-all bg-gray-50"
          />
        </div>
      </div>
      
      {/* Right side - Icons and User */}
      <div className="flex items-center gap-3">
        <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <Bell size={20} className="text-gray-600" />
        </button>
        
        <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <Settings size={20} className="text-gray-600" />
        </button>
        
        <div className="flex items-center gap-2 pl-3 ml-2 border-l border-gray-200">
          <div className="w-8 h-8 bg-gradient-to-r from-primary to-purple-600 rounded-full flex items-center justify-center">
            <User size={16} className="text-white" />
          </div>
          <span className="text-sm font-medium text-gray-700">Admin User</span>
        </div>
      </div>
    </header>
  );
};

export default Header;
